CREATE TABLE IF NOT EXISTS `sys_area` (
  `id` bigint NOT NULL COMMENT '主键',
  `pid` bigint NOT NULL DEFAULT '0' COMMENT '父级 ID，0 表示根节点',
  `name` varchar(100) NOT NULL COMMENT '地区名称',
  `letter` varchar(32) DEFAULT NULL COMMENT '地区字母',
  `adcode` bigint DEFAULT NULL COMMENT '行政区划编码',
  `location` varchar(100) DEFAULT NULL COMMENT '经纬度',
  `area_sort` int NOT NULL DEFAULT '0' COMMENT '排序号',
  `area_status` varchar(8) NOT NULL DEFAULT '1' COMMENT '状态：0-未生效，1-生效',
  `area_type` varchar(8) NOT NULL COMMENT '地区类型：0-国家，1-省/直辖市，2-城市，3-区县，4-街道，5-自定义区域',
  `hot` varchar(8) NOT NULL DEFAULT '0' COMMENT '是否热门：0-否，1-是',
  `city_code` varchar(32) DEFAULT NULL COMMENT '城市编码',
  `tenant_id` bigint NOT NULL DEFAULT '1' COMMENT '租户 ID',
  `created_by` bigint DEFAULT NULL COMMENT '创建人 ID',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人 ID',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_sys_area_pid_status` (`pid`,`area_status`),
  KEY `idx_sys_area_adcode` (`adcode`),
  KEY `idx_sys_area_type` (`area_type`),
  KEY `idx_sys_area_tenant` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='行政区划表';
